/**
 * FIRESTORE_SUBWORKFLOW - VALIDATION NODE (TOOL-SAFE)
 * ---------------------------------------------------
 * Never throws.
 * Always returns structured JSON.
 */

const input = $json;

// --------------------------------------------------
// SAFE ERROR HELPER
// --------------------------------------------------

function fail(message) {
  return [
    {
      json: {
        success: false,
        error: message
      }
    }
  ];
}

// --------------------------------------------------
// 1️⃣ BASIC STRUCTURE VALIDATION
// --------------------------------------------------

if (!input || typeof input !== "object") {
  return fail("Invalid request: body must be an object.");
}

const { action, payload } = input;

if (!action || typeof action !== "string") {
  return fail("Invalid request: 'action' is required and must be a string.");
}

// --------------------------------------------------
// 2️⃣ SUPPORTED ACTIONS
// --------------------------------------------------

const SUPPORTED_ACTIONS = [
  "GET_JOBS_BY_IDS",
  "GET_JOB_BY_ID",
  "CREATE_JOB",
  "UPDATE_JOB_STATUS",
  "GET_QUOTATIONS",
  "GET_QUOTATION_BY_ID",
  "UPDATE_QUOTATION_STATUS",
  "FINALIZE_JOB_QUOTATION",
  "ADD_QUOTATION_MESSAGE",
  "VERIFY_OTP",
  "ADD_FEEDBACK",
  "UPDATE_QUOTATION",
  "WITHDRAW_QUOTATION",
  "ADD_ADDRESS",
  "CHECK_USER_EXISTS",
  "CREATE_CLIENT_ACCOUNT",
  "CREATE_WORKER_ACCOUNT"
];

if (!SUPPORTED_ACTIONS.includes(action)) {
  return fail(`Unsupported action: ${action}`);
}

// --------------------------------------------------
// 3️⃣ HELPERS
// --------------------------------------------------

const isString = (v) => typeof v === "string" && v.trim() !== "";
const isArray = (v) => Array.isArray(v);
const isObject = (v) => v && typeof v === "object" && !Array.isArray(v);
const isNumber = (v) => typeof v === "number" && !isNaN(v);

// --------------------------------------------------
// 4️⃣ ACTION VALIDATION
// --------------------------------------------------

switch (action) {

  case "GET_JOBS_BY_IDS":
    if (!payload || !isArray(payload.job_ids) || payload.job_ids.length === 0) {
      return fail("GET_JOBS_BY_IDS requires payload.job_ids as non-empty array.");
    }
    break;

  case "GET_JOB_BY_ID":
    if (!payload || !isString(payload.job_id)) {
      return fail("GET_JOB_BY_ID requires payload.job_id (string).");
    }
    break;

  case "CREATE_JOB":
    if (!payload || !isObject(payload)) {
      return fail("CREATE_JOB requires payload object.");
    }
    if (!isString(payload.client_id)) {
      return fail("CREATE_JOB requires payload.client_id (string).");
    }
    if (!isString(payload.service_type)) {
      return fail("CREATE_JOB requires payload.service_type (string).");
    }
    if (!isString(payload.description)) {
      return fail("CREATE_JOB requires payload.description (string).");
    }
    if (typeof payload.address_index !== "number") {
      return fail("CREATE_JOB requires payload.address_index (number).");
    }
    break;

  case "UPDATE_JOB_STATUS":
    if (!payload || !isString(payload.job_id)) {
      return fail("UPDATE_JOB_STATUS requires payload.job_id (string).");
    }
    if (!isString(payload.status)) {
      return fail("UPDATE_JOB_STATUS requires payload.status (string).");
    }
    break;

  case "GET_QUOTATIONS":
    if (!payload || !isString(payload.job_id)) {
      return fail("GET_QUOTATIONS requires payload.job_id (string).");
    }
    break;

  case "GET_QUOTATION_BY_ID":
    if (!payload || !isString(payload.job_id)) {
      return fail("GET_QUOTATION_BY_ID requires payload.job_id (string).");
    }
    if (!isString(payload.quotation_id)) {
      return fail("GET_QUOTATION_BY_ID requires payload.quotation_id (string).");
    }
    break;

  case "UPDATE_QUOTATION_STATUS":
    if (!payload ||
        !isString(payload.job_id) ||
        !isString(payload.quotation_id) ||
        !isString(payload.status)) {
      return fail("UPDATE_QUOTATION_STATUS requires job_id, quotation_id and status.");
    }
    break;

  case "FINALIZE_JOB_QUOTATION":
    if (!payload || !isString(payload.job_id) || !isString(payload.quotation_id)) {
      return fail("FINALIZE_JOB_QUOTATION requires job_id and quotation_id.");
    }
    break;

  case "ADD_QUOTATION_MESSAGE":
    if (!payload || !isString(payload.job_id)) {
      return fail("ADD_QUOTATION_MESSAGE requires payload.job_id (string).");
    }
    if (!isString(payload.worker_id)) {
      return fail("ADD_QUOTATION_MESSAGE requires payload.worker_id (string).");
    }
    if (!isString(payload.estimated_cost)) {
      return fail("ADD_QUOTATION_MESSAGE requires payload.estimated_cost (string).");
    }
    if (!isString(payload.estimated_time)) {
      return fail("ADD_QUOTATION_MESSAGE requires payload.estimated_time (string).");
    }
    if (!isString(payload.description)) {
      return fail("ADD_QUOTATION_MESSAGE requires payload.description (string).");
    }
    break;

  case "VERIFY_OTP":
    if (!payload || !isString(payload.job_id)) {
      return fail("VERIFY_OTP requires payload.job_id (string).");
    }
    if (!isString(payload.otp)) {
      return fail("VERIFY_OTP requires payload.otp (string).");
    }
    break;

  case "ADD_FEEDBACK":
    if (!payload || !isString(payload.job_id)) {
      return fail("ADD_FEEDBACK requires payload.job_id (string).");
    }
    if (!isString(payload.submitted_by)) {
      return fail("ADD_FEEDBACK requires payload.submitted_by ('client' or 'worker').");
    }
    if (!['client', 'worker'].includes(payload.submitted_by)) {
      return fail("ADD_FEEDBACK payload.submitted_by must be 'client' or 'worker'.");
    }
    if (!isNumber(payload.rating) || payload.rating < 1 || payload.rating > 5) {
      return fail("ADD_FEEDBACK requires payload.rating between 1 and 5.");
    }
    if (!isString(payload.comment)) {
      return fail("ADD_FEEDBACK requires payload.comment (string).");
    }
    break;

  case "UPDATE_QUOTATION":
  if (!payload || !isString(payload.job_id)) {
    return fail("UPDATE_QUOTATION requires payload.job_id (string).");
  }
  if (!isString(payload.quotation_id)) {
    return fail("UPDATE_QUOTATION requires payload.quotation_id (string).");
  }
  if (!isString(payload.estimated_cost)) {
    return fail("UPDATE_QUOTATION requires payload.estimated_cost (string).");
  }
  if (!isString(payload.estimated_time)) {
    return fail("UPDATE_QUOTATION requires payload.estimated_time (string).");
  }
  if (!isString(payload.description)) {
    return fail("UPDATE_QUOTATION requires payload.description (string).");
  }
  break;

case "WITHDRAW_QUOTATION":
  if (!payload || !isString(payload.job_id)) {
    return fail("WITHDRAW_QUOTATION requires payload.job_id (string).");
  }
  if (!isString(payload.quotation_id)) {
    return fail("WITHDRAW_QUOTATION requires payload.quotation_id (string).");
  }
  if (!isString(payload.worker_id)) {
    return fail("WITHDRAW_QUOTATION requires payload.worker_id (string).");
  }
  if (!isString(payload.reason)) {
    return fail("WITHDRAW_QUOTATION requires payload.reason (string).");
  }
  break;

  case "ADD_ADDRESS":
    if (!payload || !isString(payload.client_id)) {
      return fail("ADD_ADDRESS requires payload.client_id (string).");
    }
    if (!isString(payload.line1)) {
      return fail("ADD_ADDRESS requires payload.line1 (string).");
    }
    if (!isString(payload.city)) {
      return fail("ADD_ADDRESS requires payload.city (string).");
    }
    if (!isString(payload.pincode)) {
      return fail("ADD_ADDRESS requires payload.pincode (string).");
    }
    break;

  case "CREATE_CLIENT_ACCOUNT":
    if (!payload || !isString(payload.name)) {
      return fail("CREATE_CLIENT_ACCOUNT requires payload.name (string).");
    }
    if (!isString(payload.phone)) {
      return fail("CREATE_CLIENT_ACCOUNT requires payload.phone (string).");
    }
    if (!/^\+?[0-9]{10,13}$/.test(payload.phone.replace(/\s/g, ''))) {
      return fail("CREATE_CLIENT_ACCOUNT requires a valid phone number.");
    }
    if (!isString(payload.line1)) {
      return fail("CREATE_CLIENT_ACCOUNT requires payload.line1 (string).");
    }
    if (!isString(payload.city)) {
      return fail("CREATE_CLIENT_ACCOUNT requires payload.city (string).");
    }
    if (!isString(payload.pincode)) {
      return fail("CREATE_CLIENT_ACCOUNT requires payload.pincode (string).");
    }
    break;

  case "CHECK_USER_EXISTS":
    if (!payload || !isString(payload.phone)) {
      return fail("CHECK_USER_EXISTS requires payload.phone (string).");
    }
    break;

  case "CREATE_WORKER_ACCOUNT":
    if (!payload || !isString(payload.name)) {
      return fail("CREATE_WORKER_ACCOUNT requires payload.name (string).");
    }
    if (!isString(payload.phone)) {
      return fail("CREATE_WORKER_ACCOUNT requires payload.phone (string).");
    }
    if (!/^\+?[0-9]{10,13}$/.test(payload.phone.replace(/\s/g, ''))) {
      return fail("CREATE_WORKER_ACCOUNT requires a valid phone number.");
    }
    if (!isArray(payload.skills) || payload.skills.length === 0) {
      return fail("CREATE_WORKER_ACCOUNT requires payload.skills (non-empty array).");
    }
    const validSkills = [
      'electrician', 'plumber', 'carpenter', 'painter',
      'acApplianceTechnician', 'houseCleaner', 'driverOnDemand',
      'cook', 'mechanic', 'handymanMasonryWork'
    ];
    const invalidSkills = payload.skills.filter(s => !validSkills.includes(s));
    if (invalidSkills.length > 0) {
      return fail(`Invalid skills: ${invalidSkills.join(', ')}. Must be from the allowed list.`);
    }
    if (!isString(payload.city)) {
      return fail("CREATE_WORKER_ACCOUNT requires payload.city (string).");
    }
    if (!isString(payload.pincode)) {
      return fail("CREATE_WORKER_ACCOUNT requires payload.pincode (string).");
    }
    break;
}

// --------------------------------------------------
// 5️⃣ SUCCESS RETURN
// --------------------------------------------------

return [
  {
    json: {
      success: true,
      ...input,
      validated: true
    }
  }
];

const jobIds = $json.payload.job_ids;

return jobIds.map(id => ({
  json: {
    job_id: id
  }
}));

return [
  {
    json: {
      success: true,
      action: "GET_JOBS_BY_IDS",
      data: $json.jobs
    }
  }
];

const items = $input.all();

const normalized = items
  .map(item => item.json.found)
  .filter(doc => doc && doc.fields)
  .map(doc => {
    const fields = doc.fields;

    const getString = (f) => f?.stringValue || null;
    const getNumber = (f) => f?.integerValue
      ? Number(f.integerValue)
      : f?.doubleValue
      ? Number(f.doubleValue)
      : null;

    return {
      id: doc.name.split('/').pop(),        // ← was doc.id, always undefined in raw mode
      service_type: getString(fields.service_type),
      description: getString(fields.description),
      status: getString(fields.status),
      worker_name: getString(fields.worker_name),
      finalized_quotation_amount: getNumber(fields.finalized_quotation_amount),
      scheduled_at: fields.scheduled_at?.timestampValue || null,
      created_at: fields.created_at?.timestampValue || null,
      city:
        fields.address?.mapValue?.fields?.city?.stringValue || null,
      pincode:
        fields.address?.mapValue?.fields?.pincode?.stringValue || null,
    };
  });

return [
  {
    json: {
      jobs: normalized
    }
  }
];

const doc = $json.found; // ✅ go inside "found"

if (!doc || !doc.fields) {
  return [
    {
      json: {
        success: false,
        error: "Job not found"
      }
    }
  ];
}

const fields = doc.fields;

const getString = (f) => f?.stringValue || null;
const getNumber = (f) =>
  f?.integerValue
    ? Number(f.integerValue)
    : f?.doubleValue
    ? Number(f.doubleValue)
    : null;

const normalized = {
  id: doc.name.split('/').pop(),
  service_type: getString(fields.service_type),
  description: getString(fields.description),
  status: getString(fields.status),
  worker_name: getString(fields.worker_name),
  finalized_quotation_amount: getNumber(fields.finalized_quotation_amount),
  scheduled_at: fields.scheduled_at?.timestampValue || null,
  created_at: fields.created_at?.timestampValue || null,
  started_at: fields.started_at?.timestampValue || null,
  city:
    fields.address?.mapValue?.fields?.city?.stringValue || null,
  pincode:
    fields.address?.mapValue?.fields?.pincode?.stringValue || null,
};

return [
  {
    json: {
      job: normalized
    }
  }
];

return [
  {
    json: {
      success: true,
      action: "GET_JOB_BY_ID",
      data: $json.job
    }
  }
];

// Firestore raw mode returns { found: {...} }
const clientDoc = $json.found || $json;

const payload = $item(0).$node["ValidateRequest"].json.payload;

if (!clientDoc || !clientDoc.fields) {
  throw new Error("Client document not found.");
}

const addresses =
  clientDoc.fields.addresses?.arrayValue?.values || [];

if (!addresses.length) {
  throw new Error("Client has no addresses saved.");
}

if (
  payload.address_index == null ||
  payload.address_index < 0 ||
  payload.address_index >= addresses.length
) {
  throw new Error("Invalid address_index.");
}

const rawAddress =
  addresses[payload.address_index]?.mapValue?.fields;

if (!rawAddress) {
  throw new Error("Selected address malformed.");
}

// Normalize address
const resolvedAddress = {
  line1: rawAddress.line1?.stringValue || null,
  line2: rawAddress.line2?.stringValue || null,
  landmark: rawAddress.landmark?.stringValue || null,
  city: rawAddress.city?.stringValue || null,
  pincode: rawAddress.pincode?.stringValue || null,
  location: rawAddress.location?.geoPointValue || null,
};

// Normalize services buckets
const servicesRaw =
  clientDoc.fields.services?.mapValue?.fields || {};

const extractJobIds = (bucket) => {
  const values = bucket?.arrayValue?.values || [];
  return values.map(v =>
    v.referenceValue.split("/").pop()
  );
};

const clientServices = {
  requested: extractJobIds(servicesRaw.requested),
  scheduled: extractJobIds(servicesRaw.scheduled),
  completed: extractJobIds(servicesRaw.completed),
  cancelled: extractJobIds(servicesRaw.cancelled),
};

return [
  {
    json: {
      ...$item(0).$node["ValidateRequest"].json,
      resolved_address: resolvedAddress,
      client_services: clientServices
    }
  }
];

return [
  {
    json: {
      success: true,
      action: "CREATE_JOB",
      data: {
        job_id: $('CreateJob').first().json.name.split('/').pop(), // extract only ID
        status: "requested",
        scheduled_at: DateTime.fromISO($('CreateJob').first().json.fields.scheduled_at.timestampValue, { zone: 'utc' }).setZone('Asia/Kolkata').toISO() || null
      }
    }
  }
];

// Get payload from ValidateRequest node
const payload = $item(0).$node["ValidateRequest"]?.json?.payload;

// Get the job document fetched from Firestore
const jobDoc = $item(0).$node["GetJobDoc1"]?.json?.found;

// --------------------------------------------------
// SAFE FAILURE HELPER
// --------------------------------------------------
function fail(message) {
  return [
    {
      json: {
        success: false,
        error: message
      }
    }
  ];
}

// --------------------------------------------------
// BASIC VALIDATION
// --------------------------------------------------
if (!payload || !payload.status) {
  return fail("Missing payload.status.");
}

if (!jobDoc || !jobDoc.fields || !jobDoc.fields.status?.stringValue) {
  return fail("Job document is missing or has no status.");
}

// --------------------------------------------------
// NORMALIZE STATUS VALUES
// --------------------------------------------------
function normalizeStatus(status) {
  if (!status) return null;
  const s = status.toString().trim();
  if (s === 'inProgress' || s === 'in_progress' || s === 'inprogress') {
    return 'inProgress';
  }
  return s;
}

const currentStatus = normalizeStatus(
  jobDoc.fields.status.stringValue
);

const newStatus = normalizeStatus(payload.status);

if (!currentStatus || !newStatus) {
  return fail("Invalid status value.");
}

// --------------------------------------------------
// ALLOWED TRANSITIONS
// --------------------------------------------------
const allowedTransitions = {
  requested:   ['cancelled', 'quoted'],
  quoted:      ['scheduled', 'cancelled'],
  scheduled:   ['cancelled', 'rescheduled'],
  rescheduled: ['cancelled'],
  inProgress:  ['completed'],
  completed:   [],
  cancelled:   []
};

if (!allowedTransitions[currentStatus]) {
  return fail(`Unknown current status: ${currentStatus}`);
}

if (!allowedTransitions[currentStatus].includes(newStatus)) {
  return fail(
    `Invalid status transition from "${currentStatus}" to "${newStatus}"`
  );
}

// --------------------------------------------------
// BUCKET MAPPING
// --------------------------------------------------
const bucketMap = {
  requested:   'requested',
  quoted:      'requested',
  scheduled:   'scheduled',
  rescheduled: 'scheduled',
  inProgress:  'scheduled',
  completed:   'completed',
  cancelled:   'cancelled'
};

return [
  {
    json: {
      ...$json,
      current_status: currentStatus,
      new_status: newStatus,
      old_bucket: bucketMap[currentStatus],
      new_bucket: bucketMap[newStatus],
      now: new Date().toISOString()
    }
  }
];

const validateNode = $item(0).$node["ValidateTransition"].json;
const jobNode = $item(0).$node["GetJobDoc1"].json.found;

const jobRef = jobNode.name;

if (validateNode.old_bucket === validateNode.new_bucket) {
  return [{
    json: {
      ...validateNode,
      bucket_changed: false
    }
  }];
}

// Read worker_uid directly from job doc — written there by FINALIZE_JOB_QUOTATION
const worker_uid = validateNode.new_status === 'completed'
  ? (jobNode.fields.worker_uid?.stringValue || null)
  : null;

return [{
  json: {
    ...validateNode,
    bucket_changed: true,
    job_reference: jobRef,
    client_uid: jobNode.fields.client_uid.stringValue,
    worker_uid
  }
}];

const vt = $item(0).$node["ValidateTransition"]?.json;
const jobDoc = $item(0).$node["GetJobDoc1"]?.json?.found;

// --------------------------------------------------
// SAFE FAILURE HELPER
// --------------------------------------------------
function fail(message) {
  return [
    {
      json: {
        success: false,
        error: message
      }
    }
  ];
}

// --------------------------------------------------
// BASIC VALIDATION
// --------------------------------------------------
if (!vt || !vt.new_status || !vt.now) {
  return fail("Missing transition data.");
}

if (!jobDoc || !jobDoc.name) {
  return fail("Job document reference missing.");
}

// --------------------------------------------------
// BUILD UPDATE FIELDS
// --------------------------------------------------
const fields = {
  status: {
    stringValue: vt.new_status
  },
  updated_at: {
    timestampValue: vt.now
  }
};

const updateMask = ["status", "updated_at"];

// --------------------------------------------------
// LIFECYCLE TIMESTAMPS
// --------------------------------------------------

// Worker arrived
if (vt.new_status === 'inProgress') {
  fields.started_at = { timestampValue: vt.now };
  updateMask.push('started_at');
}

// Work completed
if (vt.new_status === 'completed') {
  fields.completed_at = { timestampValue: vt.now };
  updateMask.push('completed_at');
}

// Job cancelled
if (vt.new_status === 'cancelled') {
  fields.cancelled_at = { timestampValue: vt.now };
  updateMask.push('cancelled_at');
}

// --------------------------------------------------
// RETURN FIRESTORE COMMIT PAYLOAD
// --------------------------------------------------
return [
  {
    json: {
      writes: [
        {
          update: {
            name: jobDoc.name,
            fields
          },
          updateMask: {
            fieldPaths: updateMask
          }
        }
      ]
    }
  }
];

const data = $item(0).$node["ValidateTransition"].json;

return [{
  json: {
    success: true,
    action: "UPDATE_JOB_STATUS",
    data: {
      job_id: $('ValidateRequest').first().json.payload.job_id,
      previous_status: data.current_status,
      new_status: data.new_status,
      bucket_moved: data.old_bucket !== data.new_bucket
    }
  }
}];

const payload = $item(0).$node["ValidateRequest"].json.payload;
const quotationDoc = $item(0).$node["GetQuoDoc"].json.found;

if (!quotationDoc || !quotationDoc.fields?.status?.stringValue) {
  throw new Error("Quotation not found.");
}

const currentStatus = quotationDoc.fields.status.stringValue;
const newStatus = payload.status;

// Only allow rejected or withdrawn
if (!["rejected", "withdrawn"].includes(newStatus)) {
  throw new Error("Invalid status update. Only 'rejected' or 'withdrawn' allowed.");
}

// Cannot modify once accepted/rejected/withdrawn
if (currentStatus !== "submitted") {
  throw new Error(
    `Cannot change quotation from '${currentStatus}'. Only 'submitted' quotations can be modified.`
  );
}

return [{
  json: {
    job_id: payload.job_id,
    quotation_id: payload.quotation_id,
    quotation_name: quotationDoc.name,
    new_status: newStatus,
    now: new Date().toISOString()
  }
}];

const data = $json;

const fields = {
  status: { stringValue: data.new_status },
  updated_at: { timestampValue: data.now }
};

const updateMask = ["status", "updated_at"];

if (data.new_status === "rejected") {
  fields.rejected_at = { timestampValue: data.now };
  updateMask.push("rejected_at");
}

if (data.new_status === "withdrawn") {
  fields.withdrawn_at = { timestampValue: data.now };
  updateMask.push("withdrawn_at");
}

return [{
  json: {
    writes: [
      {
        update: {
          name: data.quotation_name,
          fields
        },
        updateMask: {
          fieldPaths: updateMask
        }
      }
    ]
  }
}];

const payload = $('ValidateRequest').first()?.json?.payload;

return [
  {
    json: {
      success: true,
      action: "UPDATE_QUOTATION_STATUS",
      data: {
        job_id: payload.job_id,
        quotation_id: payload.quotation_id,
        status: payload.status
      }
    }
  }
];

const quotation = $json.found;

const job_id_match = quotation.name.match(/jobs\/([^/]+)\/quotations\/[^/]+$/);
if (!job_id_match) {
  throw new Error("Cannot extract job_id from quotation path.");
}
const job_id = job_id_match[1];

const worker_uid = quotation.fields.worker_uid?.stringValue || null;
const worker_name = quotation.fields.worker_name?.stringValue || null;
const worker_rating = quotation.fields.worker_rating?.doubleValue || 0;
const estimated_cost = quotation.fields.estimated_cost?.stringValue || "0";
const scheduled_at = new Date().toISOString();

const amountNumber = parseFloat(estimated_cost.replace(/[^0-9.]/g, '')) || 0;

const otp = Math.floor(1000 + Math.random() * 9000).toString();

const jobRef = `projects/voicesewa/databases/(default)/documents/jobs/${job_id}`;
const workerRef = `projects/voicesewa/databases/(default)/documents/workers/${worker_uid}`;

return [{
  json: {
    writes: [
      {
        update: {
          name: jobRef,
          fields: {
            finalized_quotation:        { referenceValue: quotation.name },
            finalized_quotation_amount: { doubleValue: amountNumber },
            status:                     { stringValue: 'scheduled' },
            scheduled_at:               { timestampValue: scheduled_at },
            worker_name:                { stringValue: worker_name },
            worker_rating:              { doubleValue: worker_rating },
            worker_uid:                 { stringValue: worker_uid },
            otp:                        { stringValue: otp },
            updated_at:                 { timestampValue: new Date().toISOString() }
          }
        },
        updateMask: {
          fieldPaths: [
            'finalized_quotation',
            'finalized_quotation_amount',
            'status',
            'scheduled_at',
            'worker_name',
            'worker_rating',
            'worker_uid',
            'otp',
            'updated_at'
          ]
        }
      },
      {
        transform: {
          document: workerRef,
          fieldTransforms: [{
            fieldPath: 'jobs.applied',
            removeAllFromArray: {
              values: [{ referenceValue: jobRef }]
            }
          }]
        }
      },
      {
        transform: {
          document: workerRef,
          fieldTransforms: [{
            fieldPath: 'jobs.confirmed',
            appendMissingElements: {
              values: [{ referenceValue: jobRef }]
            }
          }]
        }
      }
    ]
