const payload = $item(0).$node["ValidateRequest"].json.payload;
const results = $input.all();

const phoneExists = results.some(item => item.json.document);

if (phoneExists) {
  return [{
    json: {
      success: false,
      error: `An account with phone number ${payload.phone} already exists.`
    }
  }];
}

let phone = payload.phone.replace(/\s/g, '');
if (phone.startsWith('0')) phone = '91' + phone.substring(1);
if (!phone.startsWith('+')) phone = '91' + phone;

return [{
  json: {
    success: true,
    normalized_phone: phone,
    payload
  }
}];

const validateNode = $('ValidateWorkerPhoneUnique').first().json;
const payload = validateNode.payload;
const phone = validateNode.normalized_phone;
const authUser = $('CreateWorkerAuthUser').first().json;

const uid = authUser.localId;
if (!uid) {
  return [{ json: { success: false, error: "Firebase Auth user creation failed — no UID returned." } }];
}

const now = new Date().toISOString();
const workerRef = `projects/voicesewa/databases/(default)/documents/workers/${uid}`;

return [{
  json: {
    uid,
    phone,
    writes: [{
      update: {
        name: workerRef,
        fields: {
          uid:        { stringValue: uid },
          name:       { stringValue: payload.name },
          phone:      { stringValue: phone },
          bio:        { stringValue: payload.bio || "" },
          city:       { stringValue: payload.city },
          pincode:    { stringValue: payload.pincode },
          skills: {
            arrayValue: {
              values: payload.skills.map(s => ({ stringValue: s }))
            }
          },
          avg_rating:   { doubleValue: 0 },
          total_ratings: { integerValue: 0 },
          fcm_token:    { stringValue: "" },
          is_available: { booleanValue: true },
          created_at:   { timestampValue: now },
          updated_at:   { timestampValue: now },
          jobs: {
            mapValue: {
              fields: {
                applied:   { arrayValue: { values: [] } },
                confirmed: { arrayValue: { values: [] } },
                completed: { arrayValue: { values: [] } },
                declined:  { arrayValue: { values: [] } }
              }
            }
          }
        }
      }
    }]
  }
}];

const result = $('BuildWorkerDoc').first().json;

return [{
  json: {
    success: true,
    action: "CREATE_WORKER_ACCOUNT",
    data: {
      uid: result.uid,
      phone: result.phone,
      message: "Account created successfully. You can now start taking jobs."
    }
  }
}];
